class Solution:
    def finalPrices(self, prices):
        n = len(prices)
        result = prices[:]
        stack = []
        for i in range(n):
            while stack and prices[stack[-1]] >= prices[i]:
                result[stack.pop()] -= prices[i]
            stack.append(i)
        return result

